mapper.select:
SELECT lot_num, lot_code, item_name, code, current_qty, lot_date, type, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT l.lot_num, l.lot_code, i.name AS item_name, i.code, l.current_qty, l.lot_date,
i.type, COUNT(*) OVER() AS total_count FROM lot l LEFT JOIN item i ON l.item_num = i.item_num
AND l.lot_date >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND l.lot_date <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND i.type = #{item_type}
AND l.item_num = #{item_num}
AND (l.lot_code LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY l.lot_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE lot
SET current_qty = current_qty - #{deduct_qty}
WHERE lot_num = #{lot_num}
  AND current_qty >= #{deduct_qty}
  AND #{deduct_qty} > 0

mapper.select:
SELECT ROWNUM AS seq_num, depth, lot_code, item_name, item_type, gubun, id_col, content_col, date_col, status_col, worker FROM ( SELECT level_num AS depth, lot_code, item_name, item_type, gubun, id_col, content_col, date_col, status_col, worker, reg_date, flow_order FROM ( /* ── [1] 원자재 및 이전 공정 단계 종합 (투입된 자재들의 모든 공정 이력) ── */ SELECT 1 AS level_num, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, '원자재투입' AS gubun, wo.order_id AS id_col, TO_CHAR(p.flow) AS content_col, TO_CHAR(wo.order_start, 'YYYY-MM-DD HH24:MI:SS') AS date_col, wo.order_status AS status_col, e.ename AS worker, NVL(wo.order_start, l.lot_date) AS reg_date, NVL(p.flow, 999) AS flow_order FROM lot l JOIN item i ON l.item_num = i.item_num LEFT JOIN work_order wo ON l.order_num = wo.order_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN process p ON pp.item_num = p.item_num AND p.process_status = '사용중' LEFT JOIN emp e ON wo.emp_num = e.emp_num WHERE l.lot_num IN ( /* 나에게 투입된 상위 부모 롯들을 전부 역추적 */ SELECT lot_parent FROM lot_relation START WITH lot_child = #{lot_num} CONNECT BY PRIOR lot_parent = lot_child )
UNION ALL
/* ── [2] 현재 완제품 LOT의 진행 공정 종합 (공정 flow 순서대로 각 공정 단계 표시) ── */ SELECT 2 AS level_num, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, '완제품생산' AS gubun, wo.order_id AS id_col, TO_CHAR(p.flow) AS content_col, TO_CHAR(wo.order_start, 'YYYY-MM-DD HH24:MI:SS') AS date_col, wo.order_status AS status_col, e.ename AS worker, NVL(wo.order_start, l.lot_date) AS reg_date, NVL(p.flow, 999) AS flow_order FROM lot l JOIN item i ON l.item_num = i.item_num JOIN work_order wo ON l.order_num = wo.order_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN process p ON pp.item_num = p.item_num AND p.process_status = '사용중' LEFT JOIN emp e ON wo.emp_num = e.emp_num WHERE l.lot_num = #{lot_num}
UNION ALL
/* ── [3] 최종 출하 단계 종합 ── */ SELECT 3 AS level_num, l.lot_code AS lot_code, i.name AS item_name, i.type AS item_type, '출하완료' AS gubun, s.shipment_id AS id_col, v.vender_name AS content_col, TO_CHAR(s.shipment_date, 'YYYY-MM-DD HH24:MI:SS') AS date_col, s.shipment_status AS status_col, e.ename AS worker, s.shipment_date AS reg_date, 999 AS flow_order FROM lot l JOIN item i ON l.item_num = i.item_num JOIN shipment_lot sl ON sl.lot_num = l.lot_num JOIN shipment s ON sl.shipment_num = s.shipment_num JOIN shipment_request sr ON s.shipment_request_num = sr.shipment_request_num JOIN vender v ON sr.vender_num = v.vender_num LEFT JOIN emp e ON s.emp_num = e.emp_num WHERE l.lot_num IN ( SELECT lot_child FROM lot_relation START WITH lot_parent = #{lot_num} CONNECT BY PRIOR lot_child = lot_parent UNION SELECT #{lot_num} FROM DUAL ) ) /* 레벨 순서(자재->제품->출하), 시간 순서, 공정 flow 순서로 정렬 */ ORDER BY level_num ASC, reg_date ASC, flow_order ASC )
